const transactions = [
    {id:1,type:"credit",amt:100},
    {id:2,type:"debit",amt:40},
    {id:3,type:"credit",amt:50},
    {id:4,type:"debit",amt:10}
];
function netBalance(t){
    let bal = 0;
    for(let i=0;i<t.length;i++){
        if(t[i].type==="credit"){
            bal += t[i].amt;
        } else {
            bal -= t[i].amt;
        }
    }
    return bal;
}
